class Solution:
    def matrixMultiplication(self, nums):
        n = len(nums)
        m = n - 1

        if m <= 0:
            return 0

        dp = [[0] * m for _ in range(m)]

        for length in range(2, m + 1):
            for i in range(0, m - length + 1):
                j = i + length - 1
                best = float('inf')

                for k in range(i, j):
                    cost = (
                        dp[i][k]
                        + dp[k + 1][j]
                        + nums[i] * nums[k + 1] * nums[j + 1]
                    )

                    if cost < best:
                        best = cost

                dp[i][j] = best

        return dp[0][m - 1]

